public static SysOperationController construct(Args _args)
{
    SysOperationController controller;

//    if (FeatureStateProvider::isFeatureEnabled(ETG_InventAgingReportStorageFeature::instance()))
    {
        controller = new ETG_InventAgingStorageController(classstr(ETG_InventAgingStorageService),
                                                  methodstr(ETG_InventAgingStorageService, process),
                                                  SysOperationExecutionMode::Synchronous);
        controller.parmArgs(_args);
    }

    return controller;
}
